5	// Settings captures the prose-quality defaults packaged with DDx.
6	type Settings struct {
7		Mode       Mode
8		Severity   string
9		Policy     string
10		Runner     string
11		Vale       ValeConfig
12		StylePack  StylePack
13		Includes   []string
14		Excludes   []string
15		Vocabulary Vocabulary
16	}
17	
18	// DefaultSettings returns the packaged prose-quality defaults from the
19	// embedded check asset tree.
20	func DefaultSettings() (Settings, error) {
21		cfg, err := loadDefaultConfig()
22		if err != nil {
23			return Settings{}, err
24		}
25		return Settings{
26			Mode:     Mode(cfg.Mode),
27			Severity: cfg.Severity,
28			Policy:   cfg.Policy,
29			Runner:   cfg.Runner,
30			Vale: ValeConfig{
31				Version:    cfg.Vale.Version,
32				StylesPath: cfg.Vale.StylesPath,
33				Style:      cfg.Vale.Style,
34			},
35			StylePack: StylePack{
36				Name:    cfg.StylePack.Name,
37				Version: cfg.StylePack.Version,
38				Path:    cfg.StylePack.Path,
39				Rules:   append([]StyleRule(nil), cfg.StylePack.Rules...),
40			},
41			Includes: append([]string(nil), cfg.Includes...),
42			Excludes: append([]string(nil), cfg.Excludes...),
43			Vocabulary: Vocabulary{
44				DefaultPath: cfg.Vocabulary.DefaultPath,
45				ValeStyle:   cfg.Vocabulary.ValeStyle,
46				Accept:      append([]string(nil), cfg.Vocabulary.Accept...),
47				Reject:      append([]string(nil), cfg.Vocabulary.Reject...),
48			},
49		}, nil
50	}
51	
52	// ResolveSettings returns the effective prose-quality settings after layering
53	// any project configuration onto the packaged defaults.
54	func ResolveSettings(cfg *ddxconfig.Config) (Settings, error) {
55		settings, err := DefaultSettings()
56		if err != nil {
57			return Settings{}, err
58		}
59		if cfg == nil || cfg.Prose == nil {
60			return settings, nil
61		}
62	
63		if cfg.Prose.Mode != "" {
64			settings.Mode = Mode(cfg.Prose.Mode)
65		}
66		if cfg.Prose.Severity != "" {
67			settings.Severity = cfg.Prose.Severity
68		}
69		if cfg.Prose.Policy != "" {
70			settings.Policy = cfg.Prose.Policy
71		}
72		if cfg.Prose.Runner != "" {
73			settings.Runner = cfg.Prose.Runner
74		}
75		if len(cfg.Prose.Includes) > 0 {
76			settings.Includes = append([]string(nil), cfg.Prose.Includes...)
77		}
78		if len(cfg.Prose.Excludes) > 0 {
79			settings.Excludes = append([]string(nil), cfg.Prose.Excludes...)
80		}
81		if cfg.Prose.Vocabulary != nil {
82			if len(cfg.Prose.Vocabulary.Accept) > 0 {
83				settings.Vocabulary.Accept = append([]string(nil), cfg.Prose.Vocabulary.Accept...)
84			}
85			if len(cfg.Prose.Vocabulary.Reject) > 0 {
86				settings.Vocabulary.Reject = append([]string(nil), cfg.Prose.Vocabulary.Reject...)
87			}
88		}
89	
90		return settings, nil
91	}
