36		if err := json.Unmarshal(golden, &findings); err != nil {
37			t.Fatalf("unmarshal %s: %v", goldenPath, err)
38		}
39		return fixtureCase{
40			Name:     name,
41			Mode:     mode,
42			Input:    string(input),
