package docprose

import (
	"encoding/json"
	"os"
	"path/filepath"
	"strings"
	"testing"
)

// corpusCase is one labeled sample in the evaluation corpus.
type corpusCase struct {
	Group    string
	Name     string
	Input    string
	Required []string // nil = aspirational (no gate); non-nil = these rule IDs must fire
}

// corpusExpected is the schema of the optional .expected.json companion file.
type corpusExpected struct {
	RequiredRuleIDs []string `json:"required_rule_ids"`
}

// loadCorpusGroups walks testdata/corpus/ two levels deep (category/group) and
// returns all cases indexed by "category/group" key.
func loadCorpusGroups(t *testing.T, root string) map[string][]corpusCase {
	t.Helper()
	groups := map[string][]corpusCase{}

	categories, err := os.ReadDir(root)
	if err != nil {
		t.Fatalf("read corpus root %s: %v", root, err)
	}
	for _, catEntry := range categories {
		if !catEntry.IsDir() {
			continue
		}
		catDir := filepath.Join(root, catEntry.Name())
		groupEntries, err := os.ReadDir(catDir)
		if err != nil {
			t.Fatalf("read category dir %s: %v", catDir, err)
		}
		for _, groupEntry := range groupEntries {
			if !groupEntry.IsDir() {
				continue
			}
			groupKey := catEntry.Name() + "/" + groupEntry.Name()
			groupDir := filepath.Join(catDir, groupEntry.Name())
			fileEntries, err := os.ReadDir(groupDir)
			if err != nil {
				t.Fatalf("read group dir %s: %v", groupDir, err)
			}
			for _, fileEntry := range fileEntries {
				if fileEntry.IsDir() || !strings.HasSuffix(fileEntry.Name(), ".md") {
					continue
				}
				caseName := strings.TrimSuffix(fileEntry.Name(), ".md")
				inputPath := filepath.Join(groupDir, fileEntry.Name())
				data, err := os.ReadFile(inputPath)
				if err != nil {
					t.Fatalf("read corpus case %s: %v", inputPath, err)
				}
				var required []string
				expPath := filepath.Join(groupDir, caseName+".expected.json")
				if expData, err := os.ReadFile(expPath); err == nil {
					var exp corpusExpected
					if err := json.Unmarshal(expData, &exp); err != nil {
						t.Fatalf("unmarshal %s: %v", expPath, err)
					}
					required = exp.RequiredRuleIDs
				}
				groups[groupKey] = append(groups[groupKey], corpusCase{
					Group:    groupKey,
					Name:     caseName,
					Input:    string(data),
					Required: required,
				})
			}
		}
	}
	return groups
}

// TestDocProseCorpus_LoadsGroups verifies that all required corpus groups exist
// and meet the minimum case counts defined in the evaluation plan.
func TestDocProseCorpus_LoadsGroups(t *testing.T) {
	const root = "testdata/corpus"
	groups := loadCorpusGroups(t, root)

	minCounts := map[string]int{
		"positive/ai-slop":               12,
		"positive/unsupported-claim":     10,
		"positive/token-cost":            10,
		"positive/missing-actor-action":  8,
		"negative/technical-density":     10,
		"negative/markdown-structure":    12,
		"negative/evidence-backed-claim": 8,
		"real/ddx-docs":                 30,
	}

	for group, min := range minCounts {
		cases := groups[group]
		if len(cases) < min {
			t.Errorf("corpus group %q: want >= %d cases, got %d", group, min, len(cases))
		}
	}
}

// TestDocProseCorpus_ExpectedFindingSchema validates the JSON schema of every
// .expected.json companion file in the corpus.
func TestDocProseCorpus_ExpectedFindingSchema(t *testing.T) {
	const root = "testdata/corpus"
	groups := loadCorpusGroups(t, root)

	for _, cases := range groups {
		for _, tc := range cases {
			if tc.Required == nil {
				continue
			}
			tc := tc
			t.Run(tc.Group+"/"+tc.Name, func(t *testing.T) {
				if len(tc.Required) == 0 {
					t.Errorf("case %s/%s: expected.json must list at least one required_rule_id; omit the file for aspirational cases", tc.Group, tc.Name)
				}
				for _, id := range tc.Required {
					if !strings.HasPrefix(id, "prose.") {
						t.Errorf("case %s/%s: rule id %q must start with \"prose.\"", tc.Group, tc.Name, id)
					}
				}
			})
		}
	}
}

// TestDocProseCorpus_NegativeStructureCasesStayQuiet runs every negative
// corpus case through the technical-mode checker and asserts zero findings.
func TestDocProseCorpus_NegativeStructureCasesStayQuiet(t *testing.T) {
	const root = "testdata/corpus"
	groups := loadCorpusGroups(t, root)

	checker, err := NewChecker(ModeTechnical, Vocabulary{})
	if err != nil {
		t.Fatal(err)
	}

	for _, group := range []string{
		"negative/technical-density",
		"negative/markdown-structure",
		"negative/evidence-backed-claim",
	} {
		for _, tc := range groups[group] {
			tc := tc
			t.Run(group+"/"+tc.Name, func(t *testing.T) {
				findings := checker.Findings(tc.Name+".md", tc.Input)
				if len(findings) != 0 {
					t.Errorf("negative case %s/%s expected no findings, got %d: %+v",
						group, tc.Name, len(findings), findings)
				}
			})
		}
	}
}

// TestDocProseCorpus_PositiveCasesCanAssertRuleIDs runs positive corpus cases
// that have a .expected.json and verifies all required_rule_ids appear in findings.
// Cases without .expected.json are aspirational and are skipped by this test.
func TestDocProseCorpus_PositiveCasesCanAssertRuleIDs(t *testing.T) {
	const root = "testdata/corpus"
	groups := loadCorpusGroups(t, root)

	checker, err := NewChecker(ModeTechnical, Vocabulary{})
	if err != nil {
		t.Fatal(err)
	}

	for _, group := range []string{
		"positive/ai-slop",
		"positive/unsupported-claim",
		"positive/token-cost",
		"positive/missing-actor-action",
	} {
		for _, tc := range groups[group] {
			if tc.Required == nil {
				continue // aspirational, not yet gated
			}
			tc := tc
			t.Run(group+"/"+tc.Name, func(t *testing.T) {
				findings := checker.Findings(tc.Name+".md", tc.Input)
				got := make(map[string]bool, len(findings))
				for _, f := range findings {
					got[f.RuleID] = true
				}
				for _, id := range tc.Required {
					if !got[id] {
						t.Errorf("positive case %s/%s: rule %q not found in findings %v",
							group, tc.Name, id, findings)
					}
				}
			})
		}
	}
}
